                    <button onClick={() => handleStartEdit(med)} className="btn-action btn-info">تعديل</button>
                    <button onClick={() => handleDeleteMedicine(med.id!)} className="btn-action btn-danger">حذف</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

