                        ${printLayoutOverrides}
                    </style>
                </head>
                <body>
                    ${printHeader}
                    ${printContent.innerHTML}
                </body>
            </html>
        `);

        printWindow.document.close();
        printWindow.onload = () => {
            setTimeout(() => {
                printWindow.focus();
                printWindow.print();
                printWindow.close();
            }, 500);
        };
    }
  };

  const formatCurrency = (amount: number) => `${amount.toLocaleString('ar-EG')} جنيه`;

  const renderActiveReport = () => {
    switch (activeReport) {
      case 'visitsPerPatient':
        return (
