        const cleanDiagnosis = visit.diagnosis.replace(/\s*\(آخر استشارة\)/g, '').trim();
        diseaseCounts[cleanDiagnosis] = (diseaseCounts[cleanDiagnosis] || 0) + 1;
      }
    });
    return Object.entries(diseaseCounts).map(([name, count]) => ({ name, 'عدد الحالات': count }))
