    </div>
  );
};

const calculateAge = (birthDate: string): string => {
    const birth = new Date(birthDate);
    const today = new Date();

    if (isNaN(birth.getTime()) || birth > today) {
        return "تاريخ غير صالح";
    }

    const birthDay = new Date(birth.getFullYear(), birth.getMonth(), birth.getDate());
    const todayDay = new Date(today.getFullYear(), today.getMonth(), today.getDate());

    if (birthDay.getTime() === todayDay.getTime()) {
        return "مولود اليوم";
    }

    const diff = today.getTime() - birth.getTime();
    const diffDays = Math.floor(diff / (1000 * 60 * 60 * 24));

    if (diffDays < 30) {
        return `${diffDays <= 0 ? 1 : diffDays} يوم`;
    }

    let years = today.getFullYear() - birth.getFullYear();
    let months = today.getMonth() - birth.getMonth();

    if (months < 0 || (months === 0 && today.getDate() < birth.getDate())) {
        years--;
        months += 12;
    }

    if (years < 1) {
        return `${months} شهر`;
    }

    return `${years} سنة و ${months} شهر`;
};


export default PatientsView;

import Dexie, { Table } from 'dexie';
// FIX: Import WaitingListItem type for the waiting list feature.
import { Patient, Visit, Medicine, Prescription, PrescriptionTemplate, Expense, WaitingListItem, Symptom, Diagnosis } from '../types';
import { getPrices } from './settingsService';

// Helper to format local dates as YYYY-MM-DD without timezone shifts
const formatLocalISO = (date: Date): string => {
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
};

// FIX: Replaced the subclassing of Dexie with a direct instantiation and type assertion.
// This resolves TypeScript errors where methods like 'version', 'on', and 'transaction'
// were not being recognized on the subclassed type, which was causing the build to fail.
export const db = new Dexie('ClinicDB') as Dexie & {
  patients: Table<Patient, number>;
  visits: Table<Visit, number>;
  medicines: Table<Medicine, number>;
  prescriptions: Table<Prescription, number>;
  prescriptionTemplates: Table<PrescriptionTemplate, number>;
  expenses: Table<Expense, number>;
  // FIX: Added waitingList table definition.
  waitingList: Table<WaitingListItem, number>;
  symptoms: Table<Symptom, number>;
  diagnoses: Table<Diagnosis, number>;
};

// FIX: Schema definition and population logic now correctly target the 'db' instance,
// which is properly typed to include Dexie's core methods.
db.version(4).stores({
  patients: '++id, name, city',
  visits: '++id, patientId, date',
  medicines: '++id, name, form',
  prescriptions: '++id, visitId, patientId, date',
  prescriptionTemplates: '++id, name',
  expenses: '++id, date, category',
}).upgrade(tx => {
    // This migration function will run for any user with a DB version lower than 4.
    return tx.table('patients').toCollection().modify(patient => {
        // Migration for version 3: add city
        if (patient.city === undefined) {
            patient.city = 'غير محدد';
        }
        // Migration for version 4: add doctor notes
        if (patient.doctorNotes === undefined) {
            patient.doctorNotes = '';
        }
    });
});

db.version(5).stores({
    patients: '++id, &fileNumber, name, city', // Add unique fileNumber index
}).upgrade(async (tx) => {
    // This migration adds fileNumber to existing patients
    const lastPatientWithFN = await tx.table('patients').orderBy('fileNumber').last();
    let fileNumCounter = lastPatientWithFN ? lastPatientWithFN.fileNumber + 1 : 1001;
    return tx.table('patients').toCollection().modify(patient => {
        if (patient.fileNumber === undefined) {
            patient.fileNumber = fileNumCounter++;
        }
    });
});

db.version(6).stores({
    visits: '++id, patientId, date, createdAt',
});

db.version(7).stores({
    waitingList: '++id, patientId, addedAt',
});

db.version(8).stores({
    symptoms: '++id, &name',
});

db.version(9).stores({
    visits: '++id, patientId, date, createdAt, followUpForVisitId',
});

db.version(10).stores({
    prescriptions: '++id, visitId, patientId, date, followUpDate',
});

db.version(11).stores({
    diagnoses: '++id, &name',
});

db.version(12).stores({
    visits: '++id, patientId, date, createdAt, followUpForVisitId, price', // Add price index
}).upgrade(async (tx) => {
    const prices = getPrices();
    return tx.table('visits').toCollection().modify(visit => {
        if (visit.price === undefined) {
            switch (visit.type) {
                case 'كشف':
                    visit.price = prices.exam;
                    break;
                case 'استشارة':
                    visit.price = prices.consult;
                    break;
                default:
                    visit.price = 0;
                    break;
            }
        }
    });
});


db.on('populate', async () => {
    // Seed medicines if the table is empty
    const medicineCount = await db.medicines.count();
    if (medicineCount === 0) {
        await db.medicines.bulkAdd([
            // Default medicines
            { name: 'Cetal Syrup', form: 'شراب', dosages: ['٥ مل كل ٦ ساعات', '٣ مل كل ٨ ساعات'], notes: 'خافض للحرارة ومسكن' },
            { name: 'Amoxil Syrup', form: 'شراب', dosages: ['حسب الوزن', '٥ مل كل ٨ ساعات'], notes: 'مضاد حيوي واسع المجال' },
            { name: 'Brufen Syrup', form: 'شراب', dosages: ['٥ مل عند اللزوم'], notes: 'مسكن ومضاد للالتهاب' },
