// FIX: Refactored function to ensure it correctly returns a Promise<number>.
// This prevents type inference issues where the return value was being treated as 'unknown',
// which caused a `Property 'id' does not exist on type 'unknown'` error downstream.
export const addPatient = async (patient: Omit<Patient, 'id' | 'fileNumber'>): Promise<number> => {
    const newId = await db.transaction('rw', db.patients, async () => {
        const lastPatient = await db.patients.orderBy('fileNumber').last();
        const nextFileNumber = lastPatient ? lastPatient.fileNumber + 1 : 1001;
        const patientToAdd: Patient = {
            ...patient,
            fileNumber: nextFileNumber,
        };
        return db.patients.add(patientToAdd);
    });
    return newId;
};
