// --- Backup and Restore ---
interface BackupData {
    patients: Patient[];
    visits: Visit[];
    medicines: Medicine[];
    prescriptions: Prescription[];
    prescriptionTemplates: PrescriptionTemplate[];
    expenses: Expense[];
    diagnoses: Diagnosis[];
}

export const exportDB = async (): Promise<BackupData> => {
    const [patients, visits, medicines, prescriptions, prescriptionTemplates, expenses, diagnoses] = await Promise.all([
        db.patients.toArray(),
        db.visits.toArray(),
        db.medicines.toArray(),
        db.prescriptions.toArray(),
        db.prescriptionTemplates.toArray(),
        db.expenses.toArray(),
        db.diagnoses.toArray(),
    ]);
    return { patients, visits, medicines, prescriptions, prescriptionTemplates, expenses, diagnoses };
};

export const importDB = async (data: BackupData): Promise<void> => {
    // FIX: Dexie's transaction method expects tables as an array when there are many.
    // The previous implementation passed them as separate arguments, exceeding the argument limit.
    // With the new db typing, this will also now compile correctly.
    return db.transaction('rw', [db.patients, db.visits, db.medicines, db.prescriptions, db.prescriptionTemplates, db.expenses, db.diagnoses], async () => {
        // Clear all tables
        await Promise.all([
            db.patients.clear(),
            db.visits.clear(),
            db.medicines.clear(),
            db.prescriptions.clear(),
            db.prescriptionTemplates.clear(),
            db.expenses.clear(),
            db.diagnoses.clear(),
        ]);

        // Bulk add new data
        await Promise.all([
            db.patients.bulkAdd(data.patients),
            db.visits.bulkAdd(data.visits),
            db.medicines.bulkAdd(data.medicines),
            db.prescriptions.bulkAdd(data.prescriptions),
            db.prescriptionTemplates.bulkAdd(data.prescriptionTemplates),
            db.expenses.bulkAdd(data.expenses),
            db.diagnoses.bulkAdd(data.diagnoses),
        ]);
    });
};

