            </div>
        </header>
    `;

    const printWindow = window.open('', '', 'height=800,width=800');

    if (printWindow) {
        printWindow.document.write(`
            <html lang="ar" dir="rtl">
                <head>
                    <title>التقرير الشهري الشامل - ${reportMonth.toLocaleString('ar-EG', { month: 'long', year: 'numeric' })}</title>
